import React, { useEffect, useState } from 'react';
import Office from '../../../assets/images/office.png';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faCalendarCheck, faAngleUp } from '@fortawesome/free-solid-svg-icons';
import { useNavigate } from 'react-router-dom';
import './Hero.css';

function Hero() {
	const navigate = useNavigate();
	const [goUp, setGoUp] = useState(false);

	const scrollToTop = () => {
		window.scrollTo({ top: 0, behavior: 'smooth' });
	};

	const handleBookAppointmentClick = () => {
		navigate('/appointment');
	};

	useEffect(() => {
		const onPageScroll = () => {
			if (window.scrollY > 600) {
				setGoUp(true);
			} else {
				setGoUp(false);
			}
		};
		window.addEventListener('scroll', onPageScroll);

		return () => {
			window.removeEventListener('scroll', onPageScroll);
		};
	}, []);

	return (
		<div className="section-container">
			<div className="hero-section">
				<div className="text-section">
					<p className="text-headline">{`Work with us today`}</p>
					<h2 className="text-title">{`Apps development, technology and security with a lasting impact`}</h2>
					<p className="text-descritpion">{`Let's talk, we listen and then allow us to provide you with our technical expertise and solutions.
					No application is too complex as long as requirements are clear and collaborations are plenty.`}</p>
					{/* <button className="text-appointment-btn" type="button" onClick={handleBookAppointmentClick}>
						<FontAwesomeIcon icon={faCalendarCheck} /> {`Book Appointment`}
					</button> */}
					{/* <div className="text-stats">
						<div className="text-stats-container">
							<p>2023</p>
							<p>Started</p>
						</div>

						<div className="text-stats-container">
							<p>10+</p>
							<p>Expert Consultants</p>
						</div>

						<div className="text-stats-container">
							<p>20+</p>
							<p>Years of Experience</p>
						</div>
					</div> */}
				</div>
				<div className="hero-image-section">
				
					{/* <div id="container">
						<div id="circle"></div>
						<div id="small-circle"></div>
						<div id="smaller-circle"></div>
						<div id="smallest-circle"></div>
					</div> */}
				</div>
			</div>

			<div onClick={scrollToTop} className={`scroll-up ${goUp ? 'show-scroll' : ''}`}>
				<FontAwesomeIcon icon={faAngleUp} />
			</div>
			{/* <img className="hero-image3" src={Office} alt="Office" /> */}
		</div>
	);
}

export default Hero;
